import React from "react";


const Landing = () => {
  return (
  <div className="min-h-screen bg-gray-100 flex flex-col">
    <header className="bg-white shadpw">
      <div className="max-w-7xl mx-auto py-6 px-6 sm:px-6 flex items-center justify-between">
        <h1 className="text-3xl font-bold text-gray-700"> Pet Supplies Inventory Managment System</h1>
        <button className="px-5 bg-blue-700 p-2 text-slate-70 hover:text-slate-200 rounded-2xl">
          <a href="/login"> Login </a>
        </button>
      </div> 
      </header>
      <main className="flex-grow flex justify-center items-center">
      <img src="/1.JPG" alt="Pet Supplies Inventory" className="max-w-[100%] w-full h-auto h-[70%]" />

    </main>
    <footer> </footer>

  </div>

  )
};

export default Landing;
